 604→        const dockCallback = () => {
 605→            // Save session to sessionStorage
 606→            const snapshot = rocketMode.getSessionSnapshot();
 607→            const sessionData = {
 608→                ...snapshot,
 609→                galaxyUserId: selectedGalaxyUserIdRef.current,
 610→                postId: post.id,
 611→            };
 612→            sessionStorage.setItem('rocketSession', JSON.stringify(sessionData));
 613→            navigate(`/home/post/${post.id}`, { state: { fromRocket: true } });
 614→        };
 615→
 616→        if (targetStar && targetStar.viewZ < MAGNET_THRESHOLD_Z) {
 617→            // Close enough — trigger cinematic docking sequence
 618→            rocketMode.triggerDocking(idx, dockCallback);
 619→        } else {
 620→            // Far away — direct navigate (existing fallback for ENTER at distance)
 621→            const snapshot = rocketMode.getSessionSnapshot();
 622→            const sessionData = {
 623→                ...snapshot,
 624→                galaxyUserId: selectedGalaxyUserIdRef.current,
 625→                postId: post.id,
 626→            };
 627→            sessionStorage.setItem('rocketSession', JSON.stringify(sessionData));
 628→            navigate(`/home/post/${post.id}`, { state: { fromRocket: true } });
 629→        }
 630→    }, [rocketMode, navigate]);
 631→
 632→    // Set docking callback for proximity auto-dock
 633→    useEffect(() => {
 634→        rocketMode.setDockingCallback(() => {
 635→            const idx = rocketMode.dockingTargetIdxRef.current;
 636→            const stars = rocketMode.starsRef.current;
 637→            if (idx < 0 || idx >= stars.length) return;
 638→            const post = stars[idx].post;
 639→            if (!post) return;
 640→
 641→            const snapshot = rocketMode.getSessionSnapshot();
 642→            const sessionData = {
 643→                ...snapshot,
 644→                galaxyUserId: selectedGalaxyUserIdRef.current,
 645→                postId: post.id,
 646→            };
 647→            sessionStorage.setItem('rocketSession', JSON.stringify(sessionData));
 648→            navigate(`/home/post/${post.id}`, { state: { fromRocket: true } });
 649→        });
 650→    }, [rocketMode, navigate]);
 651→
 652→    // Restore rocket session on mount (reverse warp)
 653→    useEffect(() => {
 654→        const raw = sessionStorage.getItem('rocketSession');
 655→        if (!raw) return;
 656→        try {
 657→            const session = JSON.parse(raw);
 658→            // Discard if older than 5 minutes
 659→            if (Date.now() - session.timestamp > 5 * 60 * 1000) {
 660→                sessionStorage.removeItem('rocketSession');
 661→                return;
 662→            }
 663→            sessionStorage.removeItem('rocketSession');
 664→            setReverseWarpActive(true);
 665→            pendingRocketRestoreRef.current = session;
 666→        } catch {
 667→            sessionStorage.removeItem('rocketSession');
 668→        }
 669→    }, []);
 670→
 671→    // Once posts load, restore rocket mode from session
 672→    useEffect(() => {
 673→        const session = pendingRocketRestoreRef.current;
 674→        if (!session || postArray.length === 0) return;
 675→        if (stageSize.width === 0 || stageSize.height === 0) return;
 676→
 677→        const galaxyPosts = postArray.filter(p => {
 678→            const uid = p.users?.id ?? p.user_id;
 679→            return uid === session.galaxyUserId;
 680→        });
 681→
 682→        if (galaxyPosts.length === 0) {
 683→            pendingRocketRestoreRef.current = null;
 684→            setReverseWarpActive(false);
 685→            return;
 686→        }
 687→
 688→        pendingRocketRestoreRef.current = null;
 689→        selectedGalaxyUserIdRef.current = session.galaxyUserId;
 690→        setUniverseMode('pilot');
 691→        rocketMode.restoreFromSnapshot(session, galaxyPosts, stageSize);
 692→
 693→        setTimeout(() => setReverseWarpActive(false), 600);
 694→    }, [postArray, rocketMode, stageSize]);
 695→
 696→    // One-time auto focus after first payload is loaded.
 697→    // Skip if we have a constellation flyTo target — that effect handles it instead.
 698→    useEffect(() => {
 699→        if (!userId) return;
 700→        if (isInitialLoading) return;
 701→        if (hasAutoFocusedOwnGalaxyRef.current) return;
 702→        if (constellationFlyToRef.current) return;
 703→
 704→        const ownGalaxy = galaxies.find((galaxy) => galaxy.userId === userId);
 705→        const target = ownGalaxy
 706→            ? { x: ownGalaxy.x, y: ownGalaxy.y }
 707→            : (centroidTargets.get(userId) || ownGalaxyTarget);
 708→
 709→        // Wait until we have a concrete own target; fallback is resolved asynchronously.
 710→        if (!target) return;
 711→
 712→        hasAutoFocusedOwnGalaxyRef.current = true;
 713→        flyTo(target.x, target.y, MIN_UNIVERSE_ZOOM);
 714→    }, [userId, isInitialLoading, galaxies, centroidTargets, ownGalaxyTarget, flyTo]);
 715→
 716→    // Fly to constellation midpoint when arriving from a notification link.
 717→    useEffect(() => {
 718→        const target = constellationFlyToRef.current;
 719→        if (!target) return;
 720→        if (isInitialLoading) return;
 721→
 722→        const posA = finalStarPositions.get(target.starIdA);
 723→        const posB = finalStarPositions.get(target.starIdB);
 724→        if (!posA || !posB) return;
 725→
 726→        constellationFlyToRef.current = null;
 727→        hasAutoFocusedOwnGalaxyRef.current = true;
 728→
 729→        const mx = (posA.x + posB.x) / 2;
 730→        const my = (posA.y + posB.y) / 2;
 731→        flyTo(mx, my, 1.0);
 732→
 733→        // Clear navigation state so refreshing doesn't re-trigger
 734→        navigate(location.pathname, { replace: true, state: {} });
 735→    }, [isInitialLoading, finalStarPositions, flyTo, navigate, location.pathname]);
 736→
 737→    const settledPayload = useMemo(() => {
 738→        if (!isSettled || activePosts.length === 0) return [];
 739→
 740→        const payload = [];
 741→        for (const post of activePosts) {
 742→            if (!post?.id) continue;
 743→            const pos = getComputedStarPosition(post);
 744→            if (!pos || !Number.isFinite(pos.x) || !Number.isFinite(pos.y)) continue;
 745→
 746→            payload.push({
 747→                post_id: post.id,
 748→                settled_x: Math.round(pos.x * 100) / 100,
 749→                settled_y: Math.round(pos.y * 100) / 100,
 750→            });
 751→        }
 752→
 753→        payload.sort((a, b) => String(a.post_id).localeCompare(String(b.post_id)));
 754→        return payload;
 755→    }, [activePosts, getComputedStarPosition, isSettled]);
 756→
 757→    // Placeholder persistence hook: debounced Supabase RPC for settled positions.
 758→    useEffect(() => {
 759→        if (!ENABLE_SETTLED_RPC_SAVE) return;
