 761→
 762→        const signature = JSON.stringify(settledPayload);
 763→        if (signature === lastSettledPayloadRef.current) return;
 764→
 765→        if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 766→        settleDebounceRef.current = setTimeout(async () => {
 767→            lastSettledPayloadRef.current = signature;
 768→            try {
 769→                const { error } = await supabase.rpc('save_universe_settled_positions', {
 770→                    positions_payload: settledPayload,
 771→                });
 772→                if (error) {
 773→                    console.warn('[universe] settle save placeholder RPC returned error:', error.message);
 774→                }
 775→            } catch (err) {
 776→                console.warn('[universe] settle save placeholder RPC failed:', err?.message || err);
 777→            }
 778→        }, 1200);
 779→
 780→        return () => {
 781→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 782→        };
 783→    }, [isSettled, settledPayload]);
 784→
 785→    // ESC key to cancel link mode or dismiss constellation focus
 786→    useEffect(() => {
 787→        if (universeMode !== 'strategic') return;
 788→        if (!isLinkMode && !focusedConstellation) return;
