 798→
 799→    useEffect(() => {
 800→        return () => {
 801→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
 802→            if (settleDebounceRef.current) clearTimeout(settleDebounceRef.current);
 803→            rocketMode.exit();
 804→        };
 805→    }, []);
 806→
 807→    return (
