1092→                                    </button>
1093→                                ))}
1094→                            </div>
1095→                        </div>
1096→                    )}
1097→                </>
1098→            )}
1099→
1100→            {universeMode === 'pilot' && (
1101→                <RocketHUD
1102→                    rocketMode={rocketMode}
1103→                    onExit={handleExitRocket}
1104→                    onInteract={handleRocketInteract}
1105→                />
1106→            )}
1107→        </div>
1108→    );
1109→};
